def balanced(s):
    balance = 0
    for char in s:
        if char == '(':
            balance += 1
        elif char == ')':
            balance -= 1
        # Edge case: If balance goes negative, parentheses are unbalanced
        if balance < 0:
            return False
    # Final check: Balance must be zero for a balanced string
    return balance == 0
